sql_query:
SELECT "Originial publication or Follow-up"
FROM clinical_trials
WHERE "Cancer type" = 'Bladder';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Originial publication or Follow-up" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Bladder'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_is_follow_up(source_value) AS "is_follow_up"
FROM base;
